	import '../styles/app.css';

	export let data;

	const q = useQuery(data);

	$: ({ data: siteData } = $q);

	let firstOpen = true;

	onMount(() => {
		setTimeout(() => {
			firstOpen = false;
		}, 500);
	});

	$: transitionKey =
		data?.pathname &&
		data.pathname
			.replace(/\/exhibitions\/[^/]+/, '/exhibitions/*')
			.replace(/\/artists\/[^/]+/, '/artists/*');
